Add/Update Subscriber.code:
// Add or update one or more subscribers on a list.
upsertMembers({
  // The Mailchimp audience (list) id.
  listId: $.configuration.listId,
  // Array of users to upsert.
  users: [
    {
      email: $.data.email,
      status: 'subscribed',
      mergeFields: { FNAME: $.data.firstName, LNAME: $.data.lastName },
    },
  ],
});

Archive Subscriber.code:
// Archive a single subscriber by email.
archiveMember({
  listId: $.configuration.listId,
  email:  $.data.email,
});

Permanently Delete Member.code:
// Permanently delete a member (cannot be undone; member can't be re-subscribed).
deleteMember({
  listId: $.configuration.listId,
  email:  $.data.email,
});

Remove Subscriber from Tag.code:
// Remove a tag from a subscriber by marking the tag as inactive.
updateMemberTags({
  listId: $.configuration.listId,
  email:  $.data.email,
  tags: [
    { name: $.data.tagName, status: 'inactive' },
  ],
});

Unsubscribe or Delete Contact.code:
// Unsubscribe a member (set status to 'unsubscribed').
updateMember({
  listId: $.configuration.listId,
  email:  $.data.email,
  status: 'unsubscribed',
});

API Request (Beta).code:
// Make an arbitrary request to the Mailchimp API.
// Path is relative to https://{dc}.api.mailchimp.com/3.0
request('GET', '/ping');

Find Tag.code:
// Look up segments (tags) for a list.
get(`/lists/${$.configuration.listId}/segments`, {
  type: 'static',
});
